async (params, browser) => {
  // Open hotel page
  await browser.open(`${params.hotel_url}`)

  // Wait for hotel page to load
  await browser.waitForSelector('h1, [data-stid=\'content-hotel-title\']', 15000)

  // Let page render
  await browser.wait(2000)

  // Scroll to load content
  await browser.scroll({ direction: 'down', amount: 1200 })

  await browser.wait(1500)

  // Scroll further
  await browser.scroll({ direction: 'down', amount: 1200 })

  await browser.wait(1500)

  // Extract hotel details
  const hotel_data = await browser.evaluate(`const nameEl = document.querySelector('h1, [data-stid="content-hotel-title"]'); const ratingEl = document.querySelector('span.is-visually-hidden[data-stid*="rating"], [aria-label*="rating"]'); const priceEl = document.querySelector('[data-test-id="price-summary-message-line"] span, [data-stid="price-lockup"] span'); const descEl = document.querySelector('[data-stid="content-hotel-description"], [data-stid="about-section"] p, section[id*="about"] p'); const locationEl = document.querySelector('[data-stid="content-hotel-address"], [aria-label*="address"], address'); const amenityEls = document.querySelectorAll('[data-stid="section-room-amenities"] li, [data-stid="amenity-icon"] span, section[id*="amenities"] li'); const amenities = []; amenityEls.forEach(function(a) { const t = a.textContent.trim(); if (t && t.length < 80) amenities.push(t); }); const roomSection = document.querySelector('[data-stid="section-room-list"]'); const roomEls = roomSection ? roomSection.querySelectorAll('[data-stid*="room"], li, article') : document.querySelectorAll('[data-stid="section-room-list"] li'); const rooms = []; for (let i = 0; i < Math.min(roomEls.length, 5); i++) { const el = roomEls[i]; const rNameEl = el.querySelector('h3, h4, strong'); const rPriceEl = el.querySelector('[data-test-id="price-summary-message-line"] span, span[aria-hidden]'); const featureEls = el.querySelectorAll('li, [data-stid="amenity-icon"] span'); const features = []; featureEls.forEach(function(f) { const ft = f.textContent.trim(); if (ft && ft.length < 60) features.push(ft); }); rooms.push({ name: rNameEl ? rNameEl.textContent.trim() : '', price: rPriceEl ? rPriceEl.textContent.trim() : '', features: features.slice(0, 5) }); } const images = []; const imgEls = document.querySelectorAll('[data-stid*="gallery"] img, [data-stid*="media"] img, [data-stid*="carousel"] img, figure img'); imgEls.forEach(function(img) { const src = img.getAttribute('src') || ''; if (src && src.startsWith('http') && !images.includes(src)) images.push(src); }); const reviewCountEl = document.querySelector('[data-stid="reviews"] span, [aria-label*="reviews"]'); return { name: nameEl ? nameEl.textContent.trim() : '', guest_rating: ratingEl ? ratingEl.textContent.trim() : '', review_count: reviewCountEl ? reviewCountEl.textContent.trim() : '', price: priceEl ? priceEl.textContent.trim() : '', location: locationEl ? locationEl.textContent.trim() : '', description: descEl ? descEl.textContent.trim().substring(0, 1000) : '', amenities: amenities.slice(0, 15), rooms: rooms, images: images.slice(0, 8), url: window.location.href }`)

  return hotel_data
}
